+import { describe, it, expect, beforeEach } from 'vitest';
+import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
+import type { NotificationPayload } from '../../src/models/notification.js';
+
+function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
+  return {
+    id: 'notif-0001',
+    type: 'order-confirmation',
+    channel: 'sms',
+    recipient: '+15551234567',
+    subject: 'Order Confirmation',
+    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
+    ...overrides,
+  };
+}
+
+describe('SmsAdapter', () => {
+  let adapter: SmsAdapter;
+
+  beforeEach(() => {
+    adapter = new SmsAdapter({
+      fromNumber: '+15559990000',
+      provider: 'test-provider',
+    });
+  });
+
+  describe('channel', () => {
+    it('should report sms as the channel', () => {
+      expect(adapter.channel).toBe('sms');
+    });
+  });
+
+  describe('recipient resolution', () => {
+    it('should accept a valid E.164 phone number as-is', () => {
+      expect(adapter.resolveRecipient('+15551234567')).toBe('+15551234567');
+    });
+
+    it('should reject an invalid phone number without a resolver', () => {
+      expect(adapter.resolveRecipient('user-123')).toBeNull();
+    });
+
+    it('should reject a phone number without + prefix', () => {
+      expect(adapter.resolveRecipient('15551234567')).toBeNull();
+    });
+
+    it('should use the recipient resolver for non-phone recipients', () => {
+      adapter.setRecipientResolver((id) => {
+        if (id === 'user-123') return '+15551234567';
+        return null;
+      });
+
+      expect(adapter.resolveRecipient('user-123')).toBe('+15551234567');
+      expect(adapter.resolveRecipient('unknown')).toBeNull();
+    });
+
+    it('should not call resolver if recipient is already a valid phone number', () => {
+      let resolverCalled = false;
+      adapter.setRecipientResolver(() => {
+        resolverCalled = true;
+        return '+19999999999';
+      });
+
+      const result = adapter.resolveRecipient('+15551234567');
+      expect(result).toBe('+15551234567');
+      expect(resolverCalled).toBe(false);
+    });
+  });
+
+  describe('message formatting', () => {
+    it('should format subject and body into a single message', () => {
+      const message = adapter.formatMessage(makePayload());
+      expect(message).toBe('Order Confirmation: Your order has been placed. Items: Widget x2. Total: $20.00');
+    });
+
+    it('should truncate messages exceeding maxMessageLength', () => {
+      const shortAdapter = new SmsAdapter({
+        fromNumber: '+15559990000',
+        provider: 'test-provider',
+        maxMessageLength: 30,
+      });
+
+      const message = shortAdapter.formatMessage(makePayload());
+      expect(message).toHaveLength(30);
+      expect(message.endsWith('...')).toBe(true);
+    });
+
+    it('should not truncate messages within maxMessageLength', () => {
+      const longAdapter = new SmsAdapter({
+        fromNumber: '+15559990000',
+        provider: 'test-provider',
+        maxMessageLength: 500,
+      });
+
+      const message = longAdapter.formatMessage(makePayload());
+      expect(message).toBe('Order Confirmation: Your order has been placed. Items: Widget x2. Total: $20.00');
+      expect(message.endsWith('...')).toBe(false);
+    });
+
+    it('should default to 160 character limit', () => {
+      const longBody = 'A'.repeat(200);
+      const message = adapter.formatMessage(makePayload({ body: longBody }));
+      expect(message).toHaveLength(160);
+      expect(message.endsWith('...')).toBe(true);
+    });
+  });
+
+  describe('send', () => {
+    it('should send an SMS successfully', async () => {
+      const result = await adapter.send(makePayload());
+
+      expect(result.success).toBe(true);
+      expect(result.notificationId).toBe('notif-0001');
+      expect(result.channel).toBe('sms');
+      expect(result.timestamp).toBeInstanceOf(Date);
+    });
+
+    it('should record the sent message with correct fields', async () => {
+      await adapter.send(makePayload());
+
+      const messages = adapter.getSentMessages();
+      expect(messages).toHaveLength(1);
+      expect(messages[0]?.to).toBe('+15551234567');
+      expect(messages[0]?.from).toBe('+15559990000');
+      expect(messages[0]?.message).toContain('Order Confirmation');
+      expect(messages[0]?.sentAt).toBeInstanceOf(Date);
+    });
+
+    it('should preserve metadata in sent messages', async () => {
+      await adapter.send(makePayload({ metadata: { orderId: 'order-1' } }));
+
+      const messages = adapter.getSentMessages();
+      expect(messages[0]?.metadata).toEqual({ orderId: 'order-1' });
+    });
+
+    it('should fail when recipient cannot be resolved', async () => {
+      const result = await adapter.send(makePayload({ recipient: 'user-123' }));
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Invalid or unresolvable recipient');
+      expect(adapter.getSentMessages()).toHaveLength(0);
+    });
+
+    it('should call the SMS sender when set', async () => {
+      const sent: Array<{ to: string; from: string; message: string }> = [];
+      adapter.setSmsSender(async (to, from, message) => {
+        sent.push({ to, from, message });
+      });
+
+      await adapter.send(makePayload());
+
+      expect(sent).toHaveLength(1);
+      expect(sent[0]?.to).toBe('+15551234567');
+      expect(sent[0]?.from).toBe('+15559990000');
+      expect(sent[0]?.message).toContain('Order Confirmation');
+    });
+
+    it('should fail when SMS sender throws', async () => {
+      adapter.setSmsSender(async () => {
+        throw new Error('Network error');
+      });
+
+      const result = await adapter.send(makePayload());
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Network error');
+      expect(adapter.getSentMessages()).toHaveLength(0);
+    });
+
+    it('should retry on failure up to maxRetries', async () => {
+      const retryAdapter = new SmsAdapter({
+        fromNumber: '+15559990000',
+        provider: 'test-provider',
+        maxRetries: 2,
+      });
+
+      let attempts = 0;
+      retryAdapter.setSmsSender(async () => {
+        attempts++;
+        throw new Error('Timeout');
+      });
+
+      const result = await retryAdapter.send(makePayload());
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Failed after 3 attempt(s)');
+      expect(attempts).toBe(3);
+    });
+
+    it('should succeed on retry after initial failure', async () => {
+      const retryAdapter = new SmsAdapter({
+        fromNumber: '+15559990000',
+        provider: 'test-provider',
+        maxRetries: 1,
+      });
+
+      let attempts = 0;
+      retryAdapter.setSmsSender(async () => {
+        attempts++;
+        if (attempts === 1) {
+          throw new Error('Temporary failure');
+        }
+      });
+
+      const result = await retryAdapter.send(makePayload());
+
+      expect(result.success).toBe(true);
+      expect(attempts).toBe(2);
+    });
+
+    it('should use recipient resolver when recipient is not a phone number', async () => {
+      adapter.setRecipientResolver((id) => {
+        if (id === 'user-123') return '+15551234567';
+        return null;
+      });
+
+      const result = await adapter.send(makePayload({ recipient: 'user-123' }));
+
+      expect(result.success).toBe(true);
+      const messages = adapter.getSentMessages();
+      expect(messages[0]?.to).toBe('+15551234567');
+    });
+  });
+
+  describe('message management', () => {
+    it('should return a copy of sent messages', async () => {
+      await adapter.send(makePayload());
+      const messages = adapter.getSentMessages();
+      messages.pop();
+      expect(adapter.getSentMessages()).toHaveLength(1);
+    });
+
+    it('should clear sent messages', async () => {
+      await adapter.send(makePayload());
+      expect(adapter.getSentMessages()).toHaveLength(1);
+
+      adapter.clearSentMessages();
+      expect(adapter.getSentMessages()).toHaveLength(0);
+    });
+
+    it('should accumulate multiple messages', async () => {
+      await adapter.send(makePayload({ id: 'notif-0001' }));
+      await adapter.send(makePayload({ id: 'notif-0002' }));
+
+      const messages = adapter.getSentMessages();
+      expect(messages).toHaveLength(2);
+    });
+  });
+});

