/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * Features:
 * - Message formatting: maps NotificationPayload to SMS-appropriate text
 * - Phone number validation: basic E.164-style validation
 * - Recipient resolution: resolves user IDs to phone numbers via configurable resolver
 * - Configurable sender number, provider, and retry behavior
 * - In-memory message log for testing; swap internals for real providers (Twilio, SNS, etc.)
 *
 * NOTE: User preferences (src/models/user-preferences.ts) were designed assuming
 * email-only. They need to be updated to support per-channel preferences (SMS opt-in/out,
 * SMS categories, SMS quiet hours). See the warning posted to Twining for details.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface SmsConfig {
  /** Sender phone number or short code. */
  fromNumber: string;
  /** SMS provider name (for logging/identification). */
  provider: string;
  /** Maximum retry attempts for failed sends (default: 0). */
  maxRetries?: number;
  /** Maximum message length before truncation (default: 160). */
  maxMessageLength?: number;
}

export interface SentSms {
  to: string;
  from: string;
  message: string;
  sentAt: Date;
  metadata?: Record<string, string>;
}

const PHONE_REGEX = /^\+[1-9]\d{6,14}$/;

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private sentMessages: SentSms[] = [];
  private recipientResolver: ((recipient: string) => string | null) | null = null;
  private smsSender: ((to: string, from: string, message: string) => Promise<void>) | null = null;

  constructor(private config: SmsConfig) {}

  /**
   * Set a recipient resolver function.
   * The resolver maps a recipient identifier (e.g., user ID) to a phone number.
   * Return null to indicate the recipient cannot be resolved.
   */
  setRecipientResolver(resolver: (recipient: string) => string | null): void {
    this.recipientResolver = resolver;
  }

  /**
   * Set a custom SMS sender function.
   * Allows injecting real SMS provider calls or test stubs.
   * When not set, messages are recorded in-memory (test mode).
   */
  setSmsSender(sender: (to: string, from: string, message: string) => Promise<void>): void {
    this.smsSender = sender;
  }

  /**
   * Resolve a recipient identifier to a phone number.
   * If the recipient is already a valid phone number, it is returned as-is.
   * Otherwise, the recipient resolver is consulted.
   */
  resolveRecipient(recipient: string): string | null {
    if (PHONE_REGEX.test(recipient)) {
      return recipient;
    }
    if (this.recipientResolver) {
      return this.recipientResolver(recipient);
    }
    return null;
  }

  /**
   * Format a notification payload into an SMS message.
   * Truncates to maxMessageLength if needed.
   */
  formatMessage(payload: NotificationPayload): string {
    const message = `${payload.subject}: ${payload.body}`;
    const maxLen = this.config.maxMessageLength ?? 160;
    if (message.length <= maxLen) {
      return message;
    }
    return message.substring(0, maxLen - 3) + '...';
  }

  /**
   * Send an SMS notification.
   * Resolves the recipient, formats the message, and delivers the SMS.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const resolvedRecipient = this.resolveRecipient(payload.recipient);

    if (!resolvedRecipient) {
      this.logger.warn(
        `Cannot resolve recipient "${payload.recipient}" for notification ${payload.id}`,
      );
      return {
        success: false,
        notificationId: payload.id,
        channel: this.channel,
        error: `Invalid or unresolvable recipient: ${payload.recipient}`,
        timestamp: new Date(),
      };
    }

    const message = this.formatMessage(payload);

    let lastError: string | undefined;
    const maxAttempts = (this.config.maxRetries ?? 0) + 1;

    for (let attempt = 1; attempt <= maxAttempts; attempt++) {
      try {
        if (this.smsSender) {
          await this.smsSender(resolvedRecipient, this.config.fromNumber, message);
        }

        const sms: SentSms = {
          to: resolvedRecipient,
          from: this.config.fromNumber,
          message,
          sentAt: new Date(),
          metadata: payload.metadata,
        };

        this.sentMessages.push(sms);

        this.logger.info(
          `SMS sent via ${this.config.provider} to ${resolvedRecipient}: ${message.substring(0, 50)}...`,
        );

        return {
          success: true,
          notificationId: payload.id,
          channel: this.channel,
          timestamp: sms.sentAt,
        };
      } catch (err) {
        lastError = err instanceof Error ? err.message : String(err);
        this.logger.warn(
          `SMS send attempt ${attempt}/${maxAttempts} failed for ${payload.id}: ${lastError}`,
        );
      }
    }

    return {
      success: false,
      notificationId: payload.id,
      channel: this.channel,
      error: `Failed after ${maxAttempts} attempt(s): ${lastError}`,
      timestamp: new Date(),
    };
  }

  /**
   * Get all sent messages. Useful for testing.
   */
  getSentMessages(): SentSms[] {
    return [...this.sentMessages];
  }

  /**
   * Clear sent messages. Useful for testing.
   */
  clearSentMessages(): void {
    this.sentMessages = [];
  }
}

