      expect(messages[0]?.from).toBe('+15559990000');
      expect(messages[0]?.message).toContain('Order Confirmation');
      expect(messages[0]?.sentAt).toBeInstanceOf(Date);
    });

    it('should preserve metadata in sent messages', async () => {
      await adapter.send(makePayload({ metadata: { orderId: 'order-1' } }));

      const messages = adapter.getSentMessages();
      expect(messages[0]?.metadata).toEqual({ orderId: 'order-1' });
    });

    it('should fail when recipient cannot be resolved', async () => {
      const result = await adapter.send(makePayload({ recipient: 'user-123' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid or unresolvable recipient');
      expect(adapter.getSentMessages()).toHaveLength(0);
    });

    it('should call the SMS sender when set', async () => {
      const sent: Array<{ to: string; from: string; message: string }> = [];
      adapter.setSmsSender(async (to, from, message) => {
        sent.push({ to, from, message });
      });

      await adapter.send(makePayload());

      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('+15551234567');
      expect(sent[0]?.from).toBe('+15559990000');
      expect(sent[0]?.message).toContain('Order Confirmation');
    });

    it('should fail when SMS sender throws', async () => {
