      let attempts = 0;
      retryAdapter.setSmsSender(async () => {
        attempts++;
        throw new Error('Timeout');
      });

      const result = await retryAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('Failed after 3 attempt(s)');
      expect(attempts).toBe(3);
    });

    it('should succeed on retry after initial failure', async () => {
      const retryAdapter = new SmsAdapter({
        fromNumber: '+15559990000',
        provider: 'test-provider',
        maxRetries: 1,
      });

      let attempts = 0;
      retryAdapter.setSmsSender(async () => {
        attempts++;
        if (attempts === 1) {
          throw new Error('Temporary failure');
        }
      });

      const result = await retryAdapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(attempts).toBe(2);
    });

    it('should use recipient resolver when recipient is not a phone number', async () => {
      adapter.setRecipientResolver((id) => {
        if (id === 'user-123') return '+15551234567';
        return null;
      });

      const result = await adapter.send(makePayload({ recipient: 'user-123' }));

      expect(result.success).toBe(true);
      const messages = adapter.getSentMessages();
      expect(messages[0]?.to).toBe('+15551234567');
    });
  });

  describe('message management', () => {
    it('should return a copy of sent messages', async () => {
      await adapter.send(makePayload());
      const messages = adapter.getSentMessages();
      messages.pop();
      expect(adapter.getSentMessages()).toHaveLength(1);
    });

    it('should clear sent messages', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentMessages()).toHaveLength(1);

      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toHaveLength(0);
    });

    it('should accumulate multiple messages', async () => {
      await adapter.send(makePayload({ id: 'notif-0001' }));
      await adapter.send(makePayload({ id: 'notif-0002' }));

      const messages = adapter.getSentMessages();
      expect(messages).toHaveLength(2);
    });
  });
